// ── Helpers ──────────────────────────────────────────────────

let tmpDirs: string[] = [];

async function makeTmpDir(): Promise<string> {
  const raw = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-sel-test-'));
  const dir = await fs.realpath(raw);
  tmpDirs.push(dir);
  return dir;
}

afterEach(async () => {
  for (const d of tmpDirs) {
    await fs.rm(d, { recursive: true, force: true }).catch(() => {});
  }
  tmpDirs = [];
});

function makeSessionStart(overrides: Partial<SessionStartEvent> = {}): SessionStartEvent {
  return {
    type: 'session_start',
    timestamp: '2026-01-01T00:00:00.000Z',
    sessionId: 'test-session-001',
    model: 'sonnet',
    prompt: 'test prompt',
    ...overrides,
  };
}

function makeSessionEnd(overrides: Partial<SessionEndEvent> = {}): SessionEndEvent {
  return {
    type: 'session_end',
    timestamp: '2026-01-01T00:01:00.000Z',
    durationSeconds: 60,
    status: 'success',
    ...overrides,
  };
}

function makeTextDelta(overrides: Partial<TextDeltaEvent> = {}): TextDeltaEvent {
  return {
    type: 'text_delta',
    timestamp: '2026-01-01T00:00:30.000Z',
    content: 'Agent reasoning text.',
    ...overrides,
  };
}

function makeThinkingDelta(overrides: Partial<ThinkingDeltaEvent> = {}): ThinkingDeltaEvent {
  return {
    type: 'thinking_delta',
    timestamp: '2026-01-01T00:00:15.000Z',
    content: 'Extended thinking block content.',
    ...overrides,
  };
}

function makeToolCallStart(overrides: Partial<ToolCallStartEvent> = {}): ToolCallStartEvent {
  return {
    type: 'tool_call_start',
    timestamp: '2026-01-01T00:00:20.000Z',
    toolName: 'Bash',
    input: { command: 'echo hello' },
    ...overrides,
  };
}

function makeToolCallResult(overrides: Partial<ToolCallResultEvent> = {}): ToolCallResultEvent {
  return {
    type: 'tool_call_result',
    timestamp: '2026-01-01T00:00:21.000Z',
    toolName: 'Bash',
    output: 'hello\n',
    ...overrides,
  };
}

async function writeEventsJsonl(dir: string, sessionId: string, events: SessionEvent[]): Promise<string> {
  const sessionDir = path.join(dir, '.forge', 'sessions', sessionId);
  await fs.mkdir(sessionDir, { recursive: true });
  const eventsPath = path.join(sessionDir, 'events.jsonl');
  const jsonl = events.map(e => JSON.stringify(e)).join('\n') + '\n';
  await fs.writeFile(eventsPath, jsonl);
  return eventsPath;
}

function parseJsonl(content: string): SessionEvent[] {
  const parsed: SessionEvent[] = [];
  for (const line of content.split('\n')) {
    if (!line.trim()) continue;
    try {
      parsed.push(JSON.parse(line));
    } catch { /* skip malformed */ }
  }
  return parsed;
}

// ── events.jsonl file creation ──────────────────────────────

describe('structured event log: events.jsonl file', () => {
  test('events.jsonl is written to .forge/sessions/{sessionId}/', async () => {
    const dir = await makeTmpDir();
    const sessionId = 'sess-001';
    const events: SessionEvent[] = [makeSessionStart({ sessionId })];
    const eventsPath = await writeEventsJsonl(dir, sessionId, events);

    const exists = await fs.access(eventsPath).then(() => true).catch(() => false);
    expect(exists).toBe(true);
    expect(eventsPath).toContain(path.join('.forge', 'sessions', sessionId, 'events.jsonl'));
  });

  test('events.jsonl lives alongside stream.log in same session dir', async () => {
    const dir = await makeTmpDir();
    const sessionId = 'sess-002';
    const sessionDir = path.join(dir, '.forge', 'sessions', sessionId);
    await fs.mkdir(sessionDir, { recursive: true });

    // Write both files
    const streamLogPath = path.join(sessionDir, 'stream.log');
    await fs.writeFile(streamLogPath, '[2026-01-01T00:00:00Z] Session started\n');
    await writeEventsJsonl(dir, sessionId, [makeSessionStart({ sessionId })]);

    const streamExists = await fs.access(streamLogPath).then(() => true).catch(() => false);
    const eventsExists = await fs.access(path.join(sessionDir, 'events.jsonl')).then(() => true).catch(() => false);
    expect(streamExists).toBe(true);
    expect(eventsExists).toBe(true);
  });
});

// ── session_start event ─────────────────────────────────────

describe('structured event log: session_start event', () => {
  test('session_start event written first with required fields', async () => {
    const dir = await makeTmpDir();
    const sessionId = 'start-test';
    const startEvent = makeSessionStart({
      sessionId,
      model: 'opus',
      prompt: 'implement auth',
      specPath: 'specs/auth.md',
    });
    const eventsPath = await writeEventsJsonl(dir, sessionId, [startEvent]);

    const content = await fs.readFile(eventsPath, 'utf-8');
    const events = parseJsonl(content);
    expect(events.length).toBeGreaterThanOrEqual(1);

    const first = events[0] as SessionStartEvent;
    expect(first.type).toBe('session_start');
    expect(first.timestamp).toBeTruthy();
    expect(first.sessionId).toBe(sessionId);
    expect(first.model).toBe('opus');
    expect(first.prompt).toBe('implement auth');
    expect(first.specPath).toBe('specs/auth.md');
  });

  test('session_start includes commandType from sessionExtra', async () => {
    const dir = await makeTmpDir();
    const startEvent = makeSessionStart({
      sessionId: 'cmdtype-test',
      commandType: 'audit',
    });
    await writeEventsJsonl(dir, 'cmdtype-test', [startEvent]);

    const content = await fs.readFile(
      path.join(dir, '.forge', 'sessions', 'cmdtype-test', 'events.jsonl'),
      'utf-8',
    );
    const events = parseJsonl(content);
    const first = events[0] as SessionStartEvent;
    expect(first.commandType).toBe('audit');
  });
});

