// ── JSONL format and parsing ────────────────────────────────

describe('structured event log: JSONL format', () => {
  test('each line is valid JSON', async () => {
    const dir = await makeTmpDir();
    const events: SessionEvent[] = [
      makeSessionStart({ sessionId: 'jsonl-1' }),
      makeTextDelta({ content: 'Hello world' }),
      makeToolCallStart({ toolName: 'Bash', input: { command: 'ls' } }),
      makeToolCallResult({ toolName: 'Bash', output: 'file1.ts\nfile2.ts' }),
      makeSessionEnd(),
    ];
    await writeEventsJsonl(dir, 'jsonl-1', events);

    const content = await fs.readFile(
      path.join(dir, '.forge', 'sessions', 'jsonl-1', 'events.jsonl'),
      'utf-8',
    );
    const lines = content.split('\n').filter(l => l.trim());
    for (const line of lines) {
      expect(() => JSON.parse(line)).not.toThrow();
    }
  });

  test('all events share type and timestamp fields', async () => {
    const dir = await makeTmpDir();
    const events: SessionEvent[] = [
      makeSessionStart({ sessionId: 'shared-1' }),
      makeThinkingDelta(),
      makeTextDelta(),
      makeToolCallStart(),
      makeToolCallResult(),
      makeSessionEnd(),
    ];
    await writeEventsJsonl(dir, 'shared-1', events);

    const content = await fs.readFile(
      path.join(dir, '.forge', 'sessions', 'shared-1', 'events.jsonl'),
      'utf-8',
    );
    const parsed = parseJsonl(content);
    expect(parsed).toHaveLength(6);
    for (const event of parsed) {
      expect(event.type).toBeTruthy();
      expect(event.timestamp).toBeTruthy();
    }
  });

  test('events are line-delimited (one per line)', async () => {
    const dir = await makeTmpDir();
    const events: SessionEvent[] = [
      makeSessionStart({ sessionId: 'lines-1' }),
      makeTextDelta({ content: 'line 1' }),
      makeTextDelta({ content: 'line 2' }),
      makeSessionEnd(),
    ];
    await writeEventsJsonl(dir, 'lines-1', events);

    const content = await fs.readFile(
      path.join(dir, '.forge', 'sessions', 'lines-1', 'events.jsonl'),
      'utf-8',
    );
    const lines = content.split('\n').filter(l => l.trim());
    expect(lines).toHaveLength(4);
  });

  test('malformed lines are skippable during parsing', () => {
    const content = [
      JSON.stringify(makeSessionStart()),
      'not-json <<<',
      '',
      JSON.stringify(makeSessionEnd()),
    ].join('\n');

    const parsed = parseJsonl(content);
    expect(parsed).toHaveLength(2);
    expect(parsed[0].type).toBe('session_start');
    expect(parsed[1].type).toBe('session_end');
  });
});

