// ── Full session roundtrip ──────────────────────────────────

describe('structured event log: full session roundtrip', () => {
  test('complete session event sequence writes and parses correctly', async () => {
    const dir = await makeTmpDir();
    const sessionId = 'roundtrip-1';
    const events: SessionEvent[] = [
      makeSessionStart({ sessionId, model: 'opus', prompt: 'build auth', specPath: 'auth.md' }),
      makeThinkingDelta({ content: 'Planning the auth module...' }),
      makeTextDelta({ content: 'I will implement JWT auth.' }),
      makeToolCallStart({ toolName: 'Read', toolUseId: 'tu-1', input: { file_path: 'src/auth.ts' } }),
      makeToolCallResult({ toolName: 'Read', toolUseId: 'tu-1', output: 'export function login() {}' }),
      makeToolCallStart({ toolName: 'Edit', toolUseId: 'tu-2', input: { file_path: 'src/auth.ts', old_string: '{}', new_string: '{ return jwt; }' } }),
      makeToolCallResult({ toolName: 'Edit', toolUseId: 'tu-2', output: 'Edit applied.' }),
      makeToolCallStart({ toolName: 'Bash', toolUseId: 'tu-3', input: { command: 'npm test' } }),
      makeToolCallResult({ toolName: 'Bash', toolUseId: 'tu-3', output: 'All tests passed.' }),
      makeTextDelta({ content: 'Auth module implemented successfully.' }),
      makeSessionEnd({ numTurns: 5, costUsd: 2.50, durationSeconds: 180, status: 'success' }),
    ];

    const eventsPath = await writeEventsJsonl(dir, sessionId, events);
    const content = await fs.readFile(eventsPath, 'utf-8');
    const parsed = parseJsonl(content);

    expect(parsed).toHaveLength(11);
    expect(parsed[0].type).toBe('session_start');
    expect(parsed[parsed.length - 1].type).toBe('session_end');

    // Verify discriminated union types parsed correctly
    const types = parsed.map(e => e.type);
    expect(types).toEqual([
      'session_start',
      'thinking_delta',
      'text_delta',
      'tool_call_start',
      'tool_call_result',
      'tool_call_start',
      'tool_call_result',
      'tool_call_start',
      'tool_call_result',
      'text_delta',
      'session_end',
    ]);
  });
});
